"use client"

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import styles from './pill.module.css';
import { DRUG_SHAPES, COLOR_CLASSES } from '@/src/constants/pillFilters';

export default function PillSearchPage() {
    const [printFront, setPrintFront] = useState('');
    const [drugShape, setDrugShape] = useState('');
    const [colorClass1, setColorClass1] = useState('');
    
    const [results, setResults] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [hasSearched, setHasSearched] = useState(false);
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 40;

    const handleSearch = async () => {
        // ⭐️ [변경] 모든 조건이 필수일 필요가 없습니다. 
        // 다만, 아무것도 입력 안 하고 검색하는 것은 방지합니다.
        if (!printFront.trim() && !drugShape && !colorClass1) {
            alert("최소 하나의 검색 조건을 입력하거나 선택해주세요!");
            return;
        }

        setLoading(true);
        setHasSearched(true);
        setCurrentPage(1);

        try {
            const response = await axios.get(`http://localhost:8080/api/pill/search`, {
                params: { 
                    printFront: printFront.trim(),
                    drugShape: drugShape === "전체" ? "" : drugShape, 
                    colorClass1: colorClass1 === "전체" ? "" : colorClass1 
                }
            });
            setResults(response.data);
        } catch (error) {
            console.error("검색 실패:", error);
            alert("데이터를 가져오는 중 오류가 발생했습니다.");
        } finally {
            setLoading(false);
        }
    };

    // 페이지네이션 로직 (기존과 동일)
    const currentItems = results.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
    const totalPages = Math.ceil(results.length / itemsPerPage);

    return (
        <div className={styles.container}>
            <header className={styles.header}>
                <h2 className={styles.title}>💊 스마트 알약 식별 검색</h2>
                <p className={styles.subTitle}>이제 우리 DB에서 더 빠르고 정확하게 찾습니다.</p>
            </header>

            <div className={styles.searchFilter}>
                <div className={styles.inputGroup}>
                    <label>식별문자</label>
                    <input 
                        type="text" 
                        value={printFront} 
                        onChange={(e) => setPrintFront(e.target.value)} 
                        placeholder="예: TY 500" 
                        onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                    />
                </div>
                <div className={styles.inputGroup}>
                    <label>모양</label>
                    <select value={drugShape} onChange={(e) => setDrugShape(e.target.value)}>
                        <option value="">전체</option>
                        {DRUG_SHAPES.map((s) => <option key={s.value} value={s.value}>{s.label}</option>)}
                    </select>
                </div>
                <div className={styles.inputGroup}>
                    <label>색상</label>
                    <select value={colorClass1} onChange={(e) => setColorClass1(e.target.value)}>
                        <option value="">전체</option>
                        {COLOR_CLASSES.map((c) => <option key={c.value} value={c.value}>{c.label}</option>)}
                    </select>
                </div>
                <button onClick={handleSearch} className={styles.searchBtn}>
                    {loading ? "검색 중..." : "검색하기"}
                </button>
            </div>

            <div className={styles.resultContainer}>
                {loading ? (
                    <div className={styles.loadingWrapper}>데이터를 분석하고 있습니다...</div>
                ) : results.length > 0 ? (
                    <>
                        <p className={styles.totalCount}>총 <strong>{results.length}</strong>건의 결과가 발견되었습니다.</p>
                        <div className={styles.pillGrid}>
                            {currentItems.map((pill) => (
                                <div key={pill.itemSeq} className={styles.pillCard}>
                                    <div className={styles.pillImg}>
                                        <img src={pill.itemImage || "/img/no_drug_img.png"} alt={pill.itemName} />
                                    </div>
                                    <div className={styles.pillInfo}>
                                        <span className={styles.entpName}>{pill.entpName}</span>
                                        <h3 className={styles.drugName}>{pill.itemName}</h3>
                                        
                                        {/* ⭐️ 효능 설명 추가 */}
                                        {pill.efficacy && (
                                            <div className={styles.efficacyPreview}>
                                                <strong>효능:</strong> {pill.efficacy}
                                            </div>
                                        )}
                                        
                                        <div className={styles.pillTags}>
                                            <span>{pill.drugShape}</span>
                                            <span>{pill.colorClass1}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                        {/* 페이지네이션 버튼 UI 생략 (기존 유지) */}
                    </>
                ) : hasSearched && <div className={styles.noResult}>검색 결과가 없습니다.</div>}
            </div>
        </div>
    );
}